const fmt = n => new Intl.NumberFormat('es-CL',{style:'currency',currency:'CLP',maximumFractionDigits:0}).format(n||0)
const fmtUF = n => n ? `UF ${Number(n).toLocaleString('es-CL',{minimumFractionDigits:0,maximumFractionDigits:2})}` : '—'
// CLP abreviado para KPIs ($216,2M / $30K). Conserva el signo.
const fmtShort = n => { const a=Math.abs(n||0), s=n<0?'-':''; if(a>=1000000) return s+'$'+(a/1000000).toFixed(a>=10000000?0:1).replace('.',',')+'M'; if(a>=1000) return s+'$'+Math.round(a/1000)+'K'; return s+'$'+a.toLocaleString('es-CL') }
// UF abreviada para KPIs (UF 9.800 / UF 6.309), sin decimales para no recargar.
const fmtUFk = n => `UF ${Math.round(n||0).toLocaleString('es-CL')}`
// Categoría legible para rendiciones (documento al cliente). Abreviaturas internas → nombre completo.
const RENDCAT = c => c==='CBR'?'Conservador de Bienes Raíces':(c==='Notaria'||c==='Notaría')?'Notaría Lascar':(c||'Otro')
// Fecha DD-MM-AAAA a partir de un ISO 'AAAA-MM-DD'
const fmtFechaDMY = d => { if(!d) return '—'; const p=String(d).slice(0,10).split('-'); return p.length===3?`${p[2]}-${p[1]}-${p[0]}`:String(d) }
// Monto en CLP en valor absoluto (sin signo): el llamador agrega el +/- cuando corresponde. Fuente única para PDFs/resúmenes.
const fmtN = n => '$' + Math.abs(n||0).toLocaleString('es-CL')
const fmtDate = d => fmtFechaDMY(d)   // formato oficial único: 13-06-2026 (DD-MM-AAAA con guiones) en toda la app
const daysLeft = d => { if(!d) return null; return Math.round((new Date(d+'T12:00') - new Date()) / 86400000) }
// Archivo automatico de tareas: una tarea Terminada se considera archivada cuando se completo
// hace mas de DAYS_TO_ARCHIVE dias. Las terminadas sin completed_at (historicas) cuentan como archivadas.
const DAYS_TO_ARCHIVE = 15
const isTaskArchived = t => t.status==='Terminado' && (!t.completed_at || (Date.now()-new Date(t.completed_at).getTime())/86400000 > DAYS_TO_ARCHIVE)
const urgency = (due,status) => {
  if(['Completado','Pagado','Archivado','Anulado'].includes(status)) return 'done'
  const d = daysLeft(due); if(d===null) return 'normal'
  if(d<0) return 'overdue'; if(d<=5) return 'urgent'; if(d<=14) return 'soon'; return 'normal'
}
function normRut(r){ return (r||'').replace(/\s/g,'').replace(/\./g,'').toLowerCase() }
function dueFromIssued(iso){ if(!iso) return null; const d=new Date(iso+'T00:00:00'); d.setDate(d.getDate()+30); return d.toISOString().slice(0,10) }
// N° de cuota desde la glosa (las cuotas viven embebidas en el concepto, ej. "Título — Cuota 1/3"). Vacío si no aplica.
function parseCuota(concept){
  if(!concept) return ''
  const m = concept.match(/cuota\s*(\d+)\s*\/\s*(\d+)/i); if(m) return `${m[1]}/${m[2]}`
  const m2 = concept.match(/cuota\s*(\d+)/i); if(m2) return m2[1]
  const m3 = concept.match(/(\d+)\s*\/\s*(\d+)/); if(m3) return `${m3[1]}/${m3[2]}`
  return ''
}
// Al cargar/emitir una factura: si existe EXACTAMENTE UNA programada equivalente del mismo cliente,
// mismo monto y con vencimiento <= la emisión, se elimina para no duplicar en "Por facturar".
// Criterio conservador: si hay 0 o >1 candidatas, no toca nada (queda el botón manual "Ya emitida").
async function reconcileProgramada(clientId, amount, issuedAt){
  try{
    if(!clientId || !amount) return
    const {data} = await supabase.from('billing').select('id,due').eq('client_id',clientId).eq('amount',amount).eq('status','Programada')
    if(!data || !data.length) return
    // Solo cuotas con due dentro de ±45 días de la emisión: evita borrar una programada lejana
    // de otra venta del mismo cliente que casualmente tiene el mismo monto.
    if(!issuedAt) return
    const cands = data.filter(b=>b.due && Math.abs(new Date(b.due)-new Date(issuedAt))/86400000 <= 45)
      .map(b=>({...b, d:Math.abs(new Date(b.due)-new Date(issuedAt))/86400000})).sort((a,b)=>a.d-b.d)
    if(!cands.length) return
    // Empate temporal: si dos candidatas quedan casi igual de cerca (±7 días), es ambiguo → no tocar nada (queda el botón manual "Ya emitida").
    if(cands[1] && (cands[1].d - cands[0].d) <= 7) return
    // Soft-delete (no borrado físico) para que sea reversible desde la Papelera si reconcilió la cuota equivocada.
    await supabase.from('billing').update({deleted_at:new Date().toISOString()}).eq('id',cands[0].id)
  }catch(_){}
}
const urgencyColor = (due,status) => ({overdue:C.overdue,urgent:C.urgent,soon:C.soon,normal:C.normal,done:C.done})[urgency(due,status)]||C.muted
// Fuente única de "Facturado": cuota emitida (con issued_at), que no sea reembolso ni esté anulada o solo programada.
const esFacturada = b => !!b?.issued_at && b.billing_type!=='reembolso' && b.status!=='Anulada' && b.status!=='Programada'

// ─── Conciliación de facturas: motor de cruce + auto-generación de conocimiento ───
// Normaliza texto (sin tildes/símbolos) y mide similitud por tokens (Jaccard) 0..1, para cruzar glosa↔proyecto.
const _normTxt = s => (s||'').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g,'').replace(/[^a-z0-9 ]/g,' ').replace(/\s+/g,' ').trim()
const simTexto = (a,b) => { const A=new Set(_normTxt(a).split(' ').filter(w=>w.length>2)), B=new Set(_normTxt(b).split(' ').filter(w=>w.length>2)); if(!A.size||!B.size) return 0; let i=0; A.forEach(w=>{ if(B.has(w)) i++ }); return i/(A.size+B.size-i) }
// La app aprende: cada decisión se guarda como conocimiento reutilizable (learnings) + registro de fricción (usage_events).
// En modo demo el cliente Supabase es inerte, así que esto no-opera solo (no toca base real).
const learnPut = (kind,key,value,meta) => { try{ supabase.from('learnings').insert({kind,key:String(key),value:value!=null?String(value):null,meta:meta||{}}).then(()=>{},()=>{}) }catch(e){} }
const logEvent = (area,action,detail,user) => { try{ supabase.from('usage_events').insert({area,action,detail:detail||{},user_name:user||null}).then(()=>{},()=>{}) }catch(e){} }
// Razón social a mostrar en encabezados: si se pasa entityId se usa esa RS; con 1 RS, esa; si hay varias o ninguna,
// el nombre del cliente (con conteo de RS si aplica). Devuelve {name, rut, multi}.
const rsLabel = (clientId, clients, clientEntities, entityId) => {
  const ents = (clientEntities||[]).filter(e=>String(e.client_id)===String(clientId))
  if(entityId){ const e=ents.find(x=>String(x.id)===String(entityId)); if(e) return {name:e.name, rut:e.rut||'', multi:0} }
  if(ents.length===1) return {name:ents[0].name, rut:ents[0].rut||'', multi:0}
  const c = (clients||[]).find(x=>String(x.id)===String(clientId))
  return {name:c?.name||'Cliente', rut:c?.rut||'', multi:ents.length>1?ents.length:0}
}
// Folio limpio: invoice_no a veces trae la palabra "Factura" como texto; folioN devuelve solo el número/código (para contextos con prefijo "F°").
const folioN = no => String(no||'').replace(/^factura\s*/i,'').trim()
// Clave de glosa para aprender gasto→proyecto: palabras significativas (≥4) ordenadas, así "Certificado dominio CBR" matchea independiente del orden.
const glosaKey = s => _normTxt(s).split(' ').filter(w=>w.length>=4).slice(0,5).sort().join(' ')
// Clave de SERIE de facturas: glosa base sin "cuota N/M", "N/M", meses, años → para agrupar hermanas (1/3, 2/3, 3/3; o las mensuales) y no dejarlas huérfanas.
const _MESES_SERIE = /\b(ene(ro)?|feb(rero)?|mar(zo)?|abr(il)?|may(o)?|jun(io)?|jul(io)?|ago(sto)?|sept?(iembre)?|oct(ubre)?|nov(iembre)?|dic(iembre)?|january|february|march|april|may|june|july|august|september|october|november|december)\b/gi
const serieKey = concept => String(concept||'').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g,'')
  .replace(/cuota\s*\d+\s*(?:\/|-|de)\s*\d+/g,' ')
  .replace(/\b\d+\s*[\/-]\s*\d+\b/g,' ')
  .replace(/[—–-]/g,' ').replace(_MESES_SERIE,' ')
  .replace(/\b20\d{2}\b/g,' ').replace(/\b\d{2}\b/g,' ')
  .replace(/\b(pago|mensual|cuota)\b/g,' ')
  .replace(/[^a-z0-9 ]/g,' ').replace(/\s+/g,' ').trim()
// Trato al cliente: a personas se les dice "Estimado [nombre de pila]" (sin señor/señora ni apellido); a empresas "Estimados".
const _ES_EMPRESA = /\b(spa|s\.?p\.?a|ltda|limitada|s\.?a\.?|eirl|e\.?i\.?r\.?l|inversiones|comercial|constructora|sociedad|holding|inmobiliaria|servicios|grupo|asociados|abogados|consultores|ingenier|transportes|agricola|agrícola|clinica|clínica|tech|spa\.|cia)\b/i
const esPersona = name => { const n=(name||'').trim(); if(!n) return false; if(_ES_EMPRESA.test(n)) return false; const w=n.split(/\s+/); return w.length>=2 && w.length<=4 && !/\d/.test(n) }
// Género por el nombre de pila para "Estimado"/"Estimada" (heurística: termina en 'a' = mujer, salvo excepciones).
const _NOMBRES_F = new Set(['carmen','isabel','beatriz','raquel','mercedes','soledad','pilar','ines','belen','estrella','flor','luz','paz','rocio','dolores','consuelo','montserrat','maribel','noelia','ester','esther','ruth','judith','sol','nieves'])
const _NOMBRES_M = new Set(['elias','tobias','jeremias','nicolas','tomas','matias','lucas','jonas','bautista','cosme','josemaria','agustin'])
const generoF = name => { const n=_normTxt((name||'').trim().split(/\s+/)[0]); if(!n) return false; if(_NOMBRES_F.has(n)) return true; if(_NOMBRES_M.has(n)) return false; return n.endsWith('a') }
const saludoCli = name => esPersona(name) ? `${generoF(name)?'Estimada':'Estimado'} ${(name||'').trim().split(/\s+/)[0]}` : 'Estimados'
// Chip de acción para cabeceras de pestaña (estilo aprobado: tintado suave, sin borde, redondeado). variant: soft|primary|green
